  1â†’import { RingBuffer } from "lib/ring-buffer";
  2â†’import { parseCommand } from "ui/commands";
  3â†’import {
  4â†’  formatMessage,
  5â†’  formatMessageObj,
  6â†’  formatWhoResults,
  7â†’  formatWhoResultsJson,
  8â†’  formatGroupEvent,
  9â†’  formatEntityEvent,
 10â†’  formatEntityEventObj,
 11â†’  formatFriendList,
 12â†’  formatFriendListJson,
 13â†’  formatFriendEvent,
 14â†’  formatFriendEventObj,
 15â†’  formatIgnoreList,
 16â†’  formatIgnoreListJson,
 17â†’  formatIgnoreEvent,
 18â†’  formatIgnoreEventObj,
 19â†’  formatGuildRoster,
 20â†’  formatGuildRosterJson,
 21â†’} from "ui/format";
 22â†’import type { FriendEvent } from "wow/friend-store";
 23â†’import type { IgnoreEvent } from "wow/ignore-store";
 24â†’import type { GuildEvent } from "wow/guild-store";
 25â†’import { formatGuildCommandError } from "wow/protocol/guild";
 26â†’import { SessionLog, type LogEntry } from "lib/session-log";
 27â†’import type {
 28â†’  WorldHandle,
 29â†’  ChatMessage,
 30â†’  GroupEvent,
 31â†’  DuelEvent,
 32â†’} from "wow/client";
 33â†’import { ObjectType } from "wow/protocol/entity-fields";
 34â†’import type {
 35â†’  Entity,
 36â†’  UnitEntity,
 37â†’  GameObjectEntity,
 38â†’  EntityEvent,
 39â†’} from "wow/entity-store";
 40â†’
 41â†’export type EventEntry = { text: string | undefined; json: string };
 42â†’
 43â†’export type IpcSocket = {
 44â†’  write(data: string | Uint8Array): number;
 45â†’  end(): void;
 46â†’};
 47â†’
 48â†’export type IpcCommand =
 49â†’  | { type: "chat"; message: string }
 50â†’  | { type: "say"; message: string }
 51â†’  | { type: "yell"; message: string }
 52â†’  | { type: "guild"; message: string }
 53â†’  | { type: "party"; message: string }
 54â†’  | { type: "emote"; message: string }
 55â†’  | { type: "dnd"; message: string }
 56â†’  | { type: "afk"; message: string }
 57â†’  | { type: "whisper"; target: string; message: string }
 58â†’  | { type: "read" }
 59â†’  | { type: "read_json" }
 60â†’  | { type: "read_wait"; ms: number }
 61â†’  | { type: "read_wait_json"; ms: number }
 62â†’  | { type: "stop" }
 63â†’  | { type: "status" }
 64â†’  | { type: "who"; filter?: string }
 65â†’  | { type: "who_json"; filter?: string }
 66â†’  | { type: "invite"; target: string }
 67â†’  | { type: "kick"; target: string }
 68â†’  | { type: "leave" }
 69â†’  | { type: "join_channel"; channel: string; password?: string }
 70â†’  | { type: "leave_channel"; channel: string }
 71â†’  | { type: "leader"; target: string }
 72â†’  | { type: "accept" }
 73â†’  | { type: "decline" }
 74â†’  | { type: "nearby" }
 75â†’  | { type: "nearby_json" }
 76â†’  | { type: "friends" }
 77â†’  | { type: "friends_json" }
 78â†’  | { type: "add_friend"; target: string }
 79â†’  | { type: "del_friend"; target: string }
 80â†’  | { type: "ignored" }
 81â†’  | { type: "ignored_json" }
 82â†’  | { type: "add_ignore"; target: string }
 83â†’  | { type: "del_ignore"; target: string }
 84â†’  | { type: "roll"; min: number; max: number }
 85â†’  | { type: "guild_roster" }
 86â†’  | { type: "guild_roster_json" }
 87â†’  | { type: "guild_invite"; target: string }
 88â†’  | { type: "guild_kick"; target: string }
 89â†’  | { type: "guild_leave" }
 90â†’  | { type: "guild_promote"; target: string }
 91â†’  | { type: "guild_demote"; target: string }
 92â†’  | { type: "guild_leader"; target: string }
 93â†’  | { type: "guild_motd"; message: string }
 94â†’  | { type: "guild_accept" }
 95â†’  | { type: "guild_decline" }
 96â†’  | { type: "unimplemented"; feature: string };
 97â†’
 98â†’export function parseIpcCommand(line: string): IpcCommand | undefined {
 99â†’  if (line.startsWith("/")) {
100â†’    const parsed = parseCommand(line);
101â†’    switch (parsed.type) {
102â†’      case "say":
103â†’      case "yell":
104â†’      case "guild":
105â†’      case "party":
106â†’      case "emote":
107â†’      case "dnd":
108â†’      case "afk":
109â†’        return parsed;
110â†’      case "whisper":
111â†’        return parsed;
112â†’      case "who":
113â†’        return parsed.target
114â†’          ? { type: "who", filter: parsed.target }
115â†’          : { type: "who" };
116â†’      case "invite":
117â†’      case "kick":
118â†’      case "leave":
119â†’      case "leader":
120â†’      case "accept":
121â†’      case "decline":
122â†’        return parsed;
123â†’      case "join-channel":
124â†’        return {
125â†’          type: "join_channel",
126â†’          channel: parsed.channel,
127â†’          password: parsed.password,
128â†’        };
129â†’      case "leave-channel":
130â†’        return { type: "leave_channel", channel: parsed.channel };
131â†’      case "friends":
132â†’        return { type: "friends" };
133â†’      case "add-friend":
134â†’        return { type: "add_friend", target: parsed.target };
135â†’      case "remove-friend":
136â†’        return { type: "del_friend", target: parsed.target };
137â†’      case "ignored":
138â†’        return { type: "ignored" };
139â†’      case "add-ignore":
140â†’        return { type: "add_ignore", target: parsed.target };
141â†’      case "remove-ignore":
142â†’        return { type: "del_ignore", target: parsed.target };
143â†’      case "roll":
144â†’        return parsed;
145â†’      case "guild-roster":
146â†’        return { type: "guild_roster" };
147â†’      case "guild-invite":
148â†’        return { type: "guild_invite", target: parsed.target };
149â†’      case "guild-kick":
150â†’        return { type: "guild_kick", target: parsed.target };
151â†’      case "guild-leave":
152â†’        return { type: "guild_leave" };
153â†’      case "guild-promote":
154â†’        return { type: "guild_promote", target: parsed.target };
155â†’      case "guild-demote":
156â†’        return { type: "guild_demote", target: parsed.target };
157â†’      case "guild-leader":
158â†’        return { type: "guild_leader", target: parsed.target };
159â†’      case "guild-motd":
160â†’        return { type: "guild_motd", message: parsed.message };
161â†’      case "guild-accept":
162â†’        return { type: "guild_accept" };
163â†’      case "guild-decline":
164â†’        return { type: "guild_decline" };
165â†’      case "unimplemented":
166â†’        return parsed;
167â†’      default:
168â†’        return { type: "say", message: line };
169â†’    }
170â†’  }
171â†’
172â†’  const spaceIdx = line.indexOf(" ");
173â†’  const verb = spaceIdx === -1 ? line : line.slice(0, spaceIdx);
174â†’  const rest = spaceIdx === -1 ? "" : line.slice(spaceIdx + 1);
175â†’
176â†’  switch (verb) {
177â†’    case "SAY":
178â†’    case "YELL":
179â†’    case "GUILD":
180â†’    case "PARTY":
181â†’    case "EMOTE":
182â†’    case "DND":
183â†’    case "AFK":
184â†’      return {
185â†’        type: verb.toLowerCase() as
186â†’          | "say"
187â†’          | "yell"
188â†’          | "guild"
189â†’          | "party"
190â†’          | "emote"
191â†’          | "dnd"
192â†’          | "afk",
193â†’        message: rest,
194â†’      };
195â†’    case "WHISPER": {
196â†’      const targetEnd = rest.indexOf(" ");
197â†’      if (targetEnd === -1)
198â†’        return { type: "whisper", target: rest, message: "" };
199â†’      return {
200â†’        type: "whisper",
201â†’        target: rest.slice(0, targetEnd),
202â†’        message: rest.slice(targetEnd + 1),
203â†’      };
204â†’    }
205â†’    case "READ":
206â†’      return { type: "read" };
207â†’    case "READ_JSON":
208â†’      return { type: "read_json" };
209â†’    case "READ_WAIT": {
210â†’      const ms = parseInt(rest, 10);
211â†’      if (!Number.isFinite(ms) || ms < 0) return undefined;
212â†’      return { type: "read_wait", ms: Math.min(ms, 60_000) };
213â†’    }
214â†’    case "READ_WAIT_JSON": {
215â†’      const ms = parseInt(rest, 10);
216â†’      if (!Number.isFinite(ms) || ms < 0) return undefined;
217â†’      return { type: "read_wait_json", ms: Math.min(ms, 60_000) };
218â†’    }
219â†’    case "STOP":
220â†’      return { type: "stop" };
221â†’    case "STATUS":
222â†’      return { type: "status" };
223â†’    case "WHO":
224â†’      return rest ? { type: "who", filter: rest } : { type: "who" };
225â†’    case "WHO_JSON":
226â†’      return rest ? { type: "who_json", filter: rest } : { type: "who_json" };
227â†’    case "INVITE":
228â†’      return rest ? { type: "invite", target: rest } : undefined;
229â†’    case "KICK":
230â†’      return rest ? { type: "kick", target: rest } : undefined;
231â†’    case "LEAVE":
232â†’      if (rest) {
233â†’        const channel = rest.split(" ")[0]!;
234â†’        return { type: "leave_channel", channel };
235â†’      }
236â†’      return { type: "leave" };
237â†’    case "LEADER":
238â†’      return rest ? { type: "leader", target: rest } : undefined;
239â†’    case "ACCEPT":
240â†’      return { type: "accept" };
241â†’    case "DECLINE":
242â†’      return { type: "decline" };
243â†’    case "NEARBY":
244â†’      return { type: "nearby" };
245â†’    case "NEARBY_JSON":
246â†’      return { type: "nearby_json" };
247â†’    case "FRIENDS":
248â†’      return { type: "friends" };
249â†’    case "FRIENDS_JSON":
250â†’      return { type: "friends_json" };
251â†’    case "ADD_FRIEND":
252â†’      return rest ? { type: "add_friend", target: rest } : undefined;
253â†’    case "DEL_FRIEND":
254â†’      return rest ? { type: "del_friend", target: rest } : undefined;
255â†’    case "IGNORED":
256â†’      return { type: "ignored" };
257â†’    case "IGNORED_JSON":
258â†’      return { type: "ignored_json" };
259â†’    case "ADD_IGNORE":
260â†’      return rest ? { type: "add_ignore", target: rest } : undefined;
261â†’    case "DEL_IGNORE":
262â†’      return rest ? { type: "del_ignore", target: rest } : undefined;
263â†’    case "JOIN": {
264â†’      if (!rest) return undefined;
265â†’      const [channel, password] = rest.split(" ") as [string, string?];
266â†’      return { type: "join_channel", channel, password };
267â†’    }
268â†’    case "GUILD_ROSTER":
269â†’      return { type: "guild_roster" };
270â†’    case "GUILD_ROSTER_JSON":
271â†’      return { type: "guild_roster_json" };
272â†’    case "GINVITE":
273â†’      return rest ? { type: "guild_invite", target: rest } : undefined;
274â†’    case "GKICK":
275â†’      return rest ? { type: "guild_kick", target: rest } : undefined;
276â†’    case "GLEAVE":
277â†’      return { type: "guild_leave" };
278â†’    case "GPROMOTE":
279â†’      return rest ? { type: "guild_promote", target: rest } : undefined;
280â†’    case "GDEMOTE":
281â†’      return rest ? { type: "guild_demote", target: rest } : undefined;
282â†’    case "GLEADER":
283â†’      return rest ? { type: "guild_leader", target: rest } : undefined;
284â†’    case "GMOTD":
285â†’      return { type: "guild_motd", message: rest };
286â†’    case "GACCEPT":
287â†’      return { type: "guild_accept" };
288â†’    case "GDECLINE":
289â†’      return { type: "guild_decline" };
290â†’    case "MAIL":
291â†’      return { type: "unimplemented", feature: "Mail reading" };
292â†’    case "ROLL": {
293â†’      const parts = rest.split(" ").filter(Boolean);
294â†’      if (parts.length >= 2)
295â†’        return {
296â†’          type: "roll",
297â†’          min: parseInt(parts[0]!, 10),
298â†’          max: parseInt(parts[1]!, 10),
299â†’        };
300â†’      if (parts.length === 1)
301â†’        return { type: "roll", min: 1, max: parseInt(parts[0]!, 10) };
302â†’      return { type: "roll", min: 1, max: 100 };
303â†’    }
304â†’    default:
305â†’      return line ? { type: "chat", message: line } : undefined;
306â†’  }
307â†’}
308â†’
309â†’export function writeLines(socket: IpcSocket, lines: string[]): void {
310â†’  for (const line of lines) socket.write(line + "\n");
311â†’  socket.write("\n");
312â†’}
313â†’
314â†’function drainText(events: RingBuffer<EventEntry>): string[] {
315â†’  return events.drain().flatMap((e) => (e.text !== undefined ? [e.text] : []));
316â†’}
317â†’
318â†’function drainJson(events: RingBuffer<EventEntry>): string[] {
319â†’  return events.drain().map((e) => e.json);
320â†’}
321â†’
322â†’function sliceText(events: RingBuffer<EventEntry>, from: number): string[] {
323â†’  return events
324â†’    .slice(from)
325â†’    .flatMap((e) => (e.text !== undefined ? [e.text] : []));
326â†’}
327â†’
328â†’function sliceJson(events: RingBuffer<EventEntry>, from: number): string[] {
329â†’  return events.slice(from).map((e) => e.json);
330â†’}
331â†’
332â†’export async function dispatchCommand(
333â†’  cmd: IpcCommand,
334â†’  handle: WorldHandle,
335â†’  events: RingBuffer<EventEntry>,
336â†’  socket: IpcSocket,
337â†’  cleanup: () => void,
338â†’): Promise<boolean> {
339â†’  switch (cmd.type) {
340â†’    case "chat": {
341â†’      handle.sendInCurrentMode(cmd.message);
342â†’      const mode = handle.getLastChatMode();
343â†’      const label =
344â†’        mode.type === "whisper"
345â†’          ? `WHISPER ${mode.target}`
346â†’          : mode.type === "channel"
347â†’            ? `CHANNEL ${mode.channel}`
348â†’            : mode.type.toUpperCase();
349â†’      writeLines(socket, [`OK ${label}`]);
350â†’      return false;
351â†’    }
352â†’    case "say":
353â†’      handle.sendSay(cmd.message);
354â†’      writeLines(socket, ["OK"]);
355â†’      return false;
356â†’    case "yell":
357â†’      handle.sendYell(cmd.message);
358â†’      writeLines(socket, ["OK"]);
359â†’      return false;
360â†’    case "guild":
361â†’      handle.sendGuild(cmd.message);
362â†’      writeLines(socket, ["OK"]);
363â†’      return false;
364â†’    case "party":
365â†’      handle.sendParty(cmd.message);
366â†’      writeLines(socket, ["OK"]);
367â†’      return false;
368â†’    case "emote":
369â†’      handle.sendEmote(cmd.message);
370â†’      writeLines(socket, ["OK"]);
371â†’      return false;
372â†’    case "dnd":
373â†’      handle.sendDnd(cmd.message);
374â†’      writeLines(socket, ["OK"]);
375â†’      return false;
376â†’    case "afk":
377â†’      handle.sendAfk(cmd.message);
378â†’      writeLines(socket, ["OK"]);
379â†’      return false;
380â†’    case "whisper":
381â†’      handle.sendWhisper(cmd.target, cmd.message);
382â†’      writeLines(socket, ["OK"]);
383â†’      return false;
384â†’    case "roll":
385â†’      handle.sendRoll(cmd.min, cmd.max);
386â†’      writeLines(socket, ["OK"]);
387â†’      return false;
388â†’    case "read":
389â†’      writeLines(socket, drainText(events));
390â†’      return false;
391â†’    case "read_json":
392â†’      writeLines(socket, drainJson(events));
393â†’      return false;
394â†’    case "read_wait": {
395â†’      const start = events.writePos;
396â†’      await new Promise<void>((resolve) => {
397â†’        setTimeout(() => {
398â†’          writeLines(socket, sliceText(events, start));
399â†’          resolve();
400â†’        }, cmd.ms);
401â†’      });
402â†’      return false;
403â†’    }
404â†’    case "read_wait_json": {
405â†’      const start = events.writePos;
406â†’      await new Promise<void>((resolve) => {
407â†’        setTimeout(() => {
408â†’          writeLines(socket, sliceJson(events, start));
409â†’          resolve();
410â†’        }, cmd.ms);
411â†’      });
412â†’      return false;
413â†’    }
414â†’    case "stop":
415â†’      writeLines(socket, ["OK"]);
416â†’      cleanup();
417â†’      return true;
418â†’    case "status":
419â†’      writeLines(socket, ["CONNECTED"]);
420â†’      return false;
421â†’    case "who": {
422â†’      const results = await handle.who(cmd.filter ? { name: cmd.filter } : {});
423â†’      writeLines(socket, formatWhoResults(results).split("\n"));
424â†’      return false;
425â†’    }
426â†’    case "who_json": {
427â†’      const results = await handle.who(cmd.filter ? { name: cmd.filter } : {});
428â†’      writeLines(socket, [formatWhoResultsJson(results)]);
429â†’      return false;
430â†’    }
431â†’    case "invite":
432â†’      handle.invite(cmd.target);
433â†’      writeLines(socket, ["OK"]);
434â†’      return false;
435â†’    case "kick":
436â†’      handle.uninvite(cmd.target);
437â†’      writeLines(socket, ["OK"]);
438â†’      return false;
439â†’    case "leave":
440â†’      handle.leaveGroup();
441â†’      writeLines(socket, ["OK"]);
442â†’      return false;
443â†’    case "leader":
444â†’      handle.setLeader(cmd.target);
445â†’      writeLines(socket, ["OK"]);
446â†’      return false;
447â†’    case "accept":
448â†’      handle.acceptInvite();
449â†’      writeLines(socket, ["OK"]);
450â†’      return false;
451â†’    case "decline":
452â†’      handle.declineInvite();
453â†’      writeLines(socket, ["OK"]);
454â†’      return false;
455â†’    case "nearby": {
456â†’      const entities = handle.getNearbyEntities();
457â†’      writeLines(socket, entities.map(formatNearbyLine));
458â†’      return false;
459â†’    }
460â†’    case "nearby_json": {
461â†’      const entities = handle.getNearbyEntities();
462â†’      writeLines(
463â†’        socket,
464â†’        entities.map((e) => JSON.stringify(formatNearbyObj(e))),
465â†’      );
466â†’      return false;
467â†’    }
468â†’    case "friends": {
469â†’      const friends = handle.getFriends();
470â†’      writeLines(socket, formatFriendList(friends).split("\n"));
471â†’      return false;
472â†’    }
473â†’    case "friends_json": {
474â†’      const friends = handle.getFriends();
475â†’      writeLines(socket, [formatFriendListJson(friends)]);
476â†’      return false;
477â†’    }
478â†’    case "add_friend":
479â†’      handle.addFriend(cmd.target);
480â†’      writeLines(socket, ["OK"]);
481â†’      return false;
482â†’    case "del_friend":
483â†’      handle.removeFriend(cmd.target);
484â†’      writeLines(socket, ["OK"]);
485â†’      return false;
486â†’    case "ignored": {
487â†’      const ignored = handle.getIgnored();
488â†’      writeLines(socket, formatIgnoreList(ignored).split("\n"));
489â†’      return false;
490â†’    }
491â†’    case "ignored_json": {
492â†’      const ignored = handle.getIgnored();
493â†’      writeLines(socket, [formatIgnoreListJson(ignored)]);
494â†’      return false;
495â†’    }
496â†’    case "add_ignore":
497â†’      handle.addIgnore(cmd.target);
498â†’      writeLines(socket, ["OK"]);
499â†’      return false;
500â†’    case "del_ignore":
501â†’      handle.removeIgnore(cmd.target);
502â†’      writeLines(socket, ["OK"]);
503â†’      return false;
504â†’    case "join_channel":
505â†’      handle.joinChannel(cmd.channel, cmd.password);
506â†’      writeLines(socket, ["OK"]);
507â†’      return false;
508â†’    case "leave_channel":
509â†’      handle.leaveChannel(cmd.channel);
510â†’      writeLines(socket, ["OK"]);
511â†’      return false;
512â†’    case "guild_roster": {
513â†’      const roster = await handle.requestGuildRoster();
514â†’      if (roster) {
515â†’        writeLines(socket, formatGuildRoster(roster).split("\n"));
516â†’      } else {
517â†’        writeLines(socket, ["[guild] No guild roster available"]);
518â†’      }
519â†’      return false;
520â†’    }
521â†’    case "guild_roster_json": {
522â†’      const roster = await handle.requestGuildRoster();
523â†’      if (roster) {
524â†’        writeLines(socket, [formatGuildRosterJson(roster)]);
525â†’      } else {
526â†’        writeLines(socket, [
527â†’          JSON.stringify({ type: "GUILD_ROSTER", members: [] }),
528â†’        ]);
529â†’      }
530â†’      return false;
531â†’    }
532â†’    case "guild_invite":
533â†’      handle.guildInvite(cmd.target);
534â†’      writeLines(socket, ["OK"]);
535â†’      return false;
536â†’    case "guild_kick":
537â†’      handle.guildRemove(cmd.target);
538â†’      writeLines(socket, ["OK"]);
539â†’      return false;
540â†’    case "guild_leave":
541â†’      handle.guildLeave();
542â†’      writeLines(socket, ["OK"]);
543â†’      return false;
544â†’    case "guild_promote":
545â†’      handle.guildPromote(cmd.target);
546â†’      writeLines(socket, ["OK"]);
547â†’      return false;
548â†’    case "guild_demote":
549â†’      handle.guildDemote(cmd.target);
550â†’      writeLines(socket, ["OK"]);
551â†’      return false;
