        scale: 1,
        position: undefined,
        rawFields: new Map(),
        health: 100,
        maxHealth: 100,
        factionTemplate: 0,
        displayId: 0,
        npcFlags: 0,
        unitFlags: 0,
        target: 0n,
        race: 0,
        class_: 0,
        gender: 0,
        power: [],
        maxPower: [],
      },
    });

    expect(output.join("")).toContain(
      "[world] Innkeeper Palla appeared (NPC, level 55)",
    );

    input.end();
    await done;
  });

  test("entity events suppressed when disabled", async () => {
    const handle = createMockHandle();
    const input = new PassThrough();
    const output: string[] = [];

    const done = startTui(handle, false, {
      input,
      write: (s) => void output.push(s),
    });

    handle.triggerEntityEvent({
      type: "appear",
      entity: {
        guid: 1n,
        objectType: ObjectType.UNIT,
        name: "Innkeeper Palla",
        level: 55,
        entry: 0,
        scale: 1,
        position: undefined,
        rawFields: new Map(),
        health: 100,
        maxHealth: 100,
        factionTemplate: 0,
        displayId: 0,
        npcFlags: 0,
        unitFlags: 0,
        target: 0n,
        race: 0,
        class_: 0,
        gender: 0,
        power: [],
        maxPower: [],
      },
    });

    expect(output.join("")).not.toContain("[world]");

    input.end();
    await done;
  });
});

